function hideAllTabs(){document.querySelectorAll("[data-tab-id]").forEach(function(t){t.classList.remove("info__container__content__box--is-active")})}function removeActiveButtons(){document.querySelectorAll("[data-tab-button]").forEach(function(t){t.classList.remove("info__container__tabs__button--is-active")})}document.addEventListener("DOMContentLoaded",function(){var t=document.querySelectorAll("[data-tab-button]"),e=document.querySelectorAll("[data-faq-question]");t.forEach(function(e){e.addEventListener("click",function(){var t=e.dataset.tabButton,t=document.querySelector(`[data-tab-id="${t}"]`);t&&(hideAllTabs(),removeActiveButtons(),t.classList.add("info__container__content__box--is-active"),e.classList.add("info__container__tabs__button--is-active"))})}),e.forEach(function(t){t.addEventListener("click",function(){t.parentElement.classList.toggle("faq__questions__item--is-open")})})});